final:
module RefModule(
	input clk,
	input load_enable,
	input [5:0] load_value,
	output reg [5:0] count);
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (load_enable)
		count <= load_value;
	else
		count <= count + 1;
end

endmodule
